# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, balance=0):
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount
        return self.balance

    def withdraw(self, amount):
        if amount > self.balance:
            print("Insufficient funds")
            return None
        else:
            self.balance -= amount
            return self.balance

class Transaction:
    def __init__(self, account_a, account_b=None):
        self.account_a = account_a
        self.account_b = account_b

    def transfer(self, amount):
        if self.account_b is None:
            self.account_a.withdraw(amount)
        else:
            self.account_a.withdraw(amount)
            self.account_b.deposit(amount)

acct1 = Account(1000)
acct2 = Account(500)
transaction = Transaction(acct1, acct2)
transaction.transfer(300)
print(f"Account 1 balance: {acct1.balance}")
print(f"Account 2 balance: {acct2.balance}")